import { useState, useEffect, useCallback, useRef } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../../context/AuthContext";
import API from "../../api";

/* ─── EMBEDDED STYLES ─────────────────────────────────────────────────────── */
const styles = `
  @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@600;700;800&family=DM+Sans:wght@300;400;500;600;700&display=swap');

  :root {
    --font-display: 'Playfair Display', serif;
    --font-body: 'DM Sans', sans-serif;

    /* Light mode */
    --bg-base:        #f0ece4;
    --bg-glass:       rgba(255,255,255,0.60);
    --bg-glass-hover: rgba(255,255,255,0.80);
    --bg-card:        rgba(255,255,255,0.72);
    --bg-surface:     rgba(255,255,255,0.45);
    --bg-sidebar:     rgba(255,255,255,0.75);
    --border:         rgba(180,160,120,0.22);
    --border-strong:  rgba(180,160,120,0.42);
    --text-primary:   #1a1209;
    --text-secondary: #4a3f2f;
    --text-muted:     #8a7a60;
    --accent:         #c4873a;
    --accent-light:   #e6a85a;
    --accent-2:       #7c5cbf;
    --success:        #22863a;
    --success-bg:     rgba(34,134,58,0.10);
    --danger:         #c0392b;
    --warning:        #d97706;
    --warning-bg:     rgba(217,119,6,0.10);
    --shadow-sm:      0 2px 8px rgba(0,0,0,0.06);
    --shadow-md:      0 8px 32px rgba(0,0,0,0.10);
    --shadow-lg:      0 20px 60px rgba(0,0,0,0.13);
    --blur:           blur(18px);
    --gradient-brand: linear-gradient(135deg, #c4873a, #e6a85a);
    --gradient-bg:    radial-gradient(ellipse at 20% 20%, #f7e8d0 0%, #ede4d5 40%, #e0d5c5 100%);
    --mesh-1:         radial-gradient(circle at 80% 10%, rgba(196,135,58,0.12) 0%, transparent 50%);
    --mesh-2:         radial-gradient(circle at 10% 90%, rgba(124,92,191,0.08) 0%, transparent 50%);
    --noise:          url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.85' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)' opacity='0.035'/%3E%3C/svg%3E");
  }

  [data-theme="dark"] {
    --bg-base:        #110e08;
    --bg-glass:       rgba(30,22,12,0.72);
    --bg-glass-hover: rgba(40,30,16,0.88);
    --bg-card:        rgba(30,22,12,0.75);
    --bg-surface:     rgba(20,15,8,0.55);
    --bg-sidebar:     rgba(20,15,8,0.85);
    --border:         rgba(196,135,58,0.15);
    --border-strong:  rgba(196,135,58,0.30);
    --text-primary:   #f5e8d0;
    --text-secondary: #c8b090;
    --text-muted:     #7a6848;
    --accent:         #e6a85a;
    --accent-light:   #f5c878;
    --accent-2:       #a07ad0;
    --success:        #4caf72;
    --success-bg:     rgba(76,175,114,0.12);
    --danger:         #e05a4b;
    --warning:        #f59e0b;
    --warning-bg:     rgba(245,158,11,0.12);
    --shadow-sm:      0 2px 8px rgba(0,0,0,0.30);
    --shadow-md:      0 8px 32px rgba(0,0,0,0.40);
    --shadow-lg:      0 20px 60px rgba(0,0,0,0.55);
    --gradient-brand: linear-gradient(135deg, #c4873a, #f5c878);
    --gradient-bg:    radial-gradient(ellipse at 20% 20%, #1e140a 0%, #110e08 50%, #0a0805 100%);
    --mesh-1:         radial-gradient(circle at 80% 10%, rgba(196,135,58,0.18) 0%, transparent 50%);
    --mesh-2:         radial-gradient(circle at 10% 90%, rgba(124,92,191,0.12) 0%, transparent 50%);
  }

  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  body {
    font-family: var(--font-body);
    background: var(--bg-base);
    color: var(--text-primary);
  }

  .wp-root {
    min-height: 100vh;
    background: var(--gradient-bg);
    display: flex;
    flex-direction: column;
    position: relative;
    font-family: var(--font-body);
    color: var(--text-primary);
    transition: background 0.4s ease, color 0.4s ease;
  }

  .wp-root::before {
    content: '';
    position: fixed;
    inset: 0;
    background: var(--mesh-1), var(--mesh-2);
    pointer-events: none;
    z-index: 0;
  }

  .wp-root::after {
    content: '';
    position: fixed;
    inset: 0;
    background-image: var(--noise);
    background-size: 200px 200px;
    opacity: 1;
    pointer-events: none;
    z-index: 0;
  }

  /* ── HEADER ── */
  .wp-header {
    position: sticky;
    top: 0;
    z-index: 100;
    background: var(--bg-sidebar);
    backdrop-filter: var(--blur);
    -webkit-backdrop-filter: var(--blur);
    border-bottom: 1px solid var(--border-strong);
    padding: 12px 28px;
    display: flex;
    align-items: center;
    justify-content: space-between;
    box-shadow: var(--shadow-sm);
    transition: background 0.4s ease, border-color 0.4s ease;
  }

  .wp-logo {
    display: flex;
    align-items: center;
    gap: 13px;
  }

  .wp-logo-icon {
    width: 42px;
    height: 42px;
    background: var(--gradient-brand);
    border-radius: 12px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 20px;
    box-shadow: 0 4px 14px rgba(196,135,58,0.35);
    flex-shrink: 0;
  }

  .wp-logo-title {
    font-family: var(--font-display);
    font-weight: 700;
    font-size: 17px;
    color: var(--text-primary);
    line-height: 1.2;
  }

  .wp-logo-sub {
    font-size: 11px;
    color: var(--text-muted);
    margin-top: 1px;
  }

  .wp-header-actions {
    display: flex;
    align-items: center;
    gap: 10px;
  }

  /* ── GLASS CARD ── */
  .glass-card {
    background: var(--bg-glass);
    backdrop-filter: var(--blur);
    -webkit-backdrop-filter: var(--blur);
    border: 1px solid var(--border);
    border-radius: 18px;
    box-shadow: var(--shadow-md);
    transition: background 0.3s ease, border-color 0.3s ease, box-shadow 0.3s ease;
  }

  .glass-card:hover {
    background: var(--bg-glass-hover);
    box-shadow: var(--shadow-lg);
  }

  /* ── BUTTONS ── */
  .btn {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 6px;
    font-family: var(--font-body);
    font-weight: 600;
    font-size: 13px;
    border-radius: 10px;
    padding: 9px 18px;
    cursor: pointer;
    border: none;
    transition: all 0.2s ease;
    white-space: nowrap;
    letter-spacing: 0.01em;
  }

  .btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
    transform: none !important;
  }

  .btn-primary {
    background: var(--gradient-brand);
    color: #fff;
    box-shadow: 0 4px 14px rgba(196,135,58,0.35);
  }

  .btn-primary:hover:not(:disabled) {
    transform: translateY(-2px);
    box-shadow: 0 6px 20px rgba(196,135,58,0.50);
  }

  .btn-secondary {
    background: var(--bg-glass);
    backdrop-filter: var(--blur);
    color: var(--text-primary);
    border: 1px solid var(--border-strong);
    box-shadow: var(--shadow-sm);
  }

  .btn-secondary:hover:not(:disabled) {
    background: var(--bg-glass-hover);
    transform: translateY(-1px);
  }

  .btn-ghost {
    background: transparent;
    color: var(--text-muted);
    border: 1px solid var(--border);
    font-size: 18px;
    padding: 7px 12px;
  }

  .btn-ghost:hover {
    background: var(--bg-glass);
    color: var(--danger);
    border-color: var(--danger);
  }

  .btn-sm {
    font-size: 12px;
    padding: 7px 14px;
    border-radius: 8px;
  }

  .btn-takeaway {
    background: linear-gradient(135deg, #d97706, #f59e0b);
    color: #fff;
    box-shadow: 0 4px 14px rgba(217,119,6,0.35);
  }

  .btn-takeaway:hover {
    transform: translateY(-2px);
    box-shadow: 0 6px 20px rgba(217,119,6,0.50);
  }

  /* ── THEME TOGGLE ── */
  .theme-toggle {
    display: inline-flex;
    align-items: center;
    gap: 7px;
    background: var(--bg-glass);
    backdrop-filter: var(--blur);
    border: 1px solid var(--border-strong);
    border-radius: 30px;
    padding: 6px 12px;
    cursor: pointer;
    font-size: 15px;
    color: var(--text-primary);
    transition: all 0.2s ease;
    box-shadow: var(--shadow-sm);
  }

  .theme-toggle:hover {
    background: var(--bg-glass-hover);
    transform: scale(1.03);
  }

  .toggle-track {
    width: 32px;
    height: 18px;
    background: var(--border-strong);
    border-radius: 30px;
    position: relative;
    transition: background 0.3s;
  }

  [data-theme="dark"] .toggle-track {
    background: var(--accent);
  }

  .toggle-thumb {
    width: 12px;
    height: 12px;
    background: #fff;
    border-radius: 50%;
    position: absolute;
    top: 3px;
    left: 3px;
    transition: transform 0.3s;
    box-shadow: 0 1px 4px rgba(0,0,0,0.3);
  }

  [data-theme="dark"] .toggle-thumb {
    transform: translateX(14px);
  }

  /* ── PAGE CONTENT ── */
  .wp-content {
    flex: 1;
    overflow: auto;
    padding: 24px 28px;
    position: relative;
    z-index: 1;
  }

  /* ── SECTION HEADING ── */
  .section-heading {
    font-family: var(--font-display);
    font-size: 22px;
    font-weight: 700;
    color: var(--text-primary);
  }

  /* ── SPECIALS BANNER ── */
  .specials-banner {
    background: linear-gradient(135deg, rgba(217,119,6,0.12), rgba(245,158,11,0.08));
    backdrop-filter: var(--blur);
    border: 1px solid rgba(217,119,6,0.30);
    border-radius: 14px;
    padding: 14px 18px;
    margin-bottom: 20px;
    display: flex;
    align-items: center;
    gap: 10px;
    flex-wrap: wrap;
    box-shadow: 0 4px 16px rgba(217,119,6,0.10);
  }

  .special-badge {
    background: linear-gradient(135deg, #d97706, #f59e0b);
    color: #fff;
    border-radius: 20px;
    padding: 4px 12px;
    font-size: 12px;
    font-weight: 700;
    box-shadow: 0 2px 8px rgba(217,119,6,0.30);
  }

  /* ── TABLE GRID ── */
  .table-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(140px, 1fr));
    gap: 14px;
  }

  .table-tile {
    background: var(--bg-glass);
    backdrop-filter: var(--blur);
    -webkit-backdrop-filter: var(--blur);
    border: 1px solid var(--border);
    border-radius: 16px;
    padding: 20px 14px 16px;
    text-align: center;
    cursor: pointer;
    transition: all 0.25s cubic-bezier(0.34,1.56,0.64,1);
    box-shadow: var(--shadow-sm);
    position: relative;
    overflow: hidden;
  }

  .table-tile::before {
    content: '';
    position: absolute;
    inset: 0;
    background: var(--gradient-brand);
    opacity: 0;
    transition: opacity 0.25s;
    border-radius: 16px;
  }

  .table-tile:hover {
    transform: translateY(-4px) scale(1.02);
    box-shadow: var(--shadow-lg);
    border-color: var(--accent);
  }

  .table-tile.occupied {
    border-color: rgba(196,135,58,0.45);
    background: rgba(196,135,58,0.08);
  }

  .table-tile.reserved {
    border-color: rgba(124,92,191,0.45);
    background: rgba(124,92,191,0.08);
  }

  .table-tile.available {
    border-color: rgba(34,134,58,0.30);
  }

  .tile-num {
    font-family: var(--font-display);
    font-size: 28px;
    font-weight: 800;
    color: var(--text-primary);
    line-height: 1;
    margin-bottom: 6px;
    position: relative;
    z-index: 1;
  }

  .tile-status {
    font-size: 10px;
    font-weight: 700;
    letter-spacing: 1px;
    text-transform: uppercase;
    padding: 3px 8px;
    border-radius: 20px;
    display: inline-block;
    position: relative;
    z-index: 1;
  }

  .table-tile.available .tile-status { background: rgba(34,134,58,0.15); color: var(--success); }
  .table-tile.occupied .tile-status  { background: rgba(196,135,58,0.18); color: var(--accent); }
  .table-tile.reserved .tile-status  { background: rgba(124,92,191,0.18); color: var(--accent-2); }

  /* ── ORDER LAYOUT ── */
  .order-layout {
    display: grid;
    grid-template-columns: 1fr 400px;
    gap: 22px;
    min-height: 100%;
    align-items: start;
  }

  /* ── BADGE ── */
  .badge {
    display: inline-flex;
    align-items: center;
    gap: 5px;
    border-radius: 20px;
    padding: 5px 13px;
    font-size: 12px;
    font-weight: 700;
    border: 1px solid transparent;
  }

  .badge-table {
    background: var(--gradient-brand);
    color: #fff;
    box-shadow: 0 3px 10px rgba(196,135,58,0.30);
    font-family: var(--font-display);
    font-size: 14px;
    padding: 8px 18px;
    border-radius: 12px;
  }

  .badge-takeaway {
    background: linear-gradient(135deg, #d97706, #f59e0b);
    color: #fff;
    box-shadow: 0 3px 10px rgba(217,119,6,0.30);
    font-family: var(--font-display);
    font-size: 14px;
    padding: 8px 18px;
    border-radius: 12px;
  }

  .badge-sent {
    border-color: currentColor;
    background: transparent;
  }

  /* ── MENU CATEGORY ── */
  .menu-cat-label {
    font-size: 10px;
    font-weight: 700;
    color: var(--text-muted);
    text-transform: uppercase;
    letter-spacing: 2px;
    margin-bottom: 12px;
    display: flex;
    align-items: center;
    gap: 8px;
  }

  .menu-cat-label::after {
    content: '';
    flex: 1;
    height: 1px;
    background: var(--border);
  }

  .menu-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(170px, 1fr));
    gap: 12px;
  }

  /* ── MENU ITEM CARD ── */
  .menu-item-card {
    background: var(--bg-glass);
    backdrop-filter: var(--blur);
    -webkit-backdrop-filter: var(--blur);
    border: 1px solid var(--border);
    border-radius: 14px;
    padding: 14px 16px;
    cursor: pointer;
    text-align: left;
    transition: all 0.22s cubic-bezier(0.34,1.56,0.64,1);
    color: var(--text-primary);
    position: relative;
    overflow: visible;
    font-family: var(--font-body);
    box-shadow: var(--shadow-sm);
  }

  .menu-item-card:hover:not(:disabled) {
    border-color: var(--accent);
    transform: translateY(-3px);
    box-shadow: 0 10px 28px rgba(196,135,58,0.20);
    background: var(--bg-glass-hover);
  }

  .menu-item-card:disabled {
    opacity: 0.40;
    cursor: not-allowed;
    transform: none;
  }

  .menu-item-card.is-special {
    background: linear-gradient(135deg, rgba(217,119,6,0.10), rgba(245,158,11,0.06));
    border-color: rgba(217,119,6,0.35);
  }

  .menu-item-card.is-special:hover:not(:disabled) {
    border-color: var(--warning);
    box-shadow: 0 10px 28px rgba(217,119,6,0.25);
  }

  .special-ribbon {
    position: absolute;
    top: -9px;
    right: 10px;
    background: linear-gradient(135deg, #d97706, #f59e0b);
    color: #fff;
    font-size: 9px;
    font-weight: 800;
    border-radius: 20px;
    padding: 3px 9px;
    letter-spacing: 0.5px;
    box-shadow: 0 2px 8px rgba(217,119,6,0.40);
    text-transform: uppercase;
  }

  .item-name {
    font-weight: 600;
    font-size: 13px;
    margin-bottom: 6px;
    line-height: 1.3;
  }

  .item-price {
    color: var(--success);
    font-weight: 800;
    font-size: 14px;
  }

  .item-price-old {
    text-decoration: line-through;
    font-size: 11px;
    color: var(--text-muted);
  }

  /* ── ORDER PANEL ── */
  .order-panel {
    background: var(--bg-glass);
    backdrop-filter: var(--blur);
    -webkit-backdrop-filter: var(--blur);
    border: 1px solid var(--border-strong);
    border-radius: 20px;
    box-shadow: var(--shadow-lg);
    overflow: hidden;
    position: sticky;
    top: 80px;
    transition: background 0.4s ease;
  }

  .order-panel-header {
    padding: 16px 20px;
    background: var(--bg-surface);
    border-bottom: 1px solid var(--border);
    display: flex;
    justify-content: space-between;
    align-items: center;
  }

  .order-panel-title {
    font-family: var(--font-display);
    font-size: 16px;
    font-weight: 700;
    color: var(--text-primary);
  }

  .order-panel-sub {
    font-size: 11px;
    color: var(--text-muted);
    margin-top: 2px;
  }

  /* ── ROUND HEADER ── */
  .round-header {
    padding: 9px 18px;
    border-bottom: 1px solid var(--border);
    display: flex;
    justify-content: space-between;
    align-items: center;
  }

  .round-label {
    font-size: 11px;
    font-weight: 800;
    text-transform: uppercase;
    letter-spacing: 0.8px;
  }

  /* ── ORDER ITEM ROW ── */
  .order-item-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 10px 18px;
    border-bottom: 1px solid var(--border);
    transition: background 0.15s;
  }

  .order-item-row:hover {
    background: rgba(196,135,58,0.04);
  }

  .remove-btn {
    background: none;
    border: none;
    cursor: pointer;
    color: var(--danger);
    font-size: 18px;
    width: 26px;
    height: 26px;
    display: flex;
    align-items: center;
    justify-content: center;
    border-radius: 50%;
    transition: all 0.15s;
    opacity: 0.7;
    flex-shrink: 0;
  }

  .remove-btn:hover {
    background: rgba(192,57,43,0.12);
    opacity: 1;
    transform: scale(1.15);
  }

  /* ── TOTAL BAR ── */
  .order-total-bar {
    padding: 16px 20px;
    background: var(--bg-surface);
    border-top: 1px solid var(--border);
    border-bottom: 1px solid var(--border);
  }

  .grand-total-amount {
    font-family: var(--font-display);
    font-size: 22px;
    font-weight: 800;
    color: var(--accent);
  }

  /* ── NEW ROUND PROMPT ── */
  .new-round-prompt {
    background: linear-gradient(135deg, rgba(196,135,58,0.08), rgba(124,92,191,0.05));
    border: 1px solid var(--accent);
    border-radius: 14px;
    padding: 14px 18px;
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 12px;
    margin-bottom: 18px;
    box-shadow: 0 4px 16px rgba(196,135,58,0.10);
  }

  /* ── MODAL ── */
  .modal-overlay {
    position: fixed;
    inset: 0;
    background: rgba(0,0,0,0.55);
    backdrop-filter: blur(6px);
    -webkit-backdrop-filter: blur(6px);
    z-index: 1000;
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 20px;
    animation: fadeIn 0.2s ease;
  }

  @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
  @keyframes slideUp { from { transform: translateY(16px); opacity: 0; } to { transform: translateY(0); opacity: 1; } }

  .modal {
    background: var(--bg-glass);
    backdrop-filter: var(--blur);
    -webkit-backdrop-filter: var(--blur);
    border: 1px solid var(--border-strong);
    border-radius: 22px;
    box-shadow: var(--shadow-lg);
    width: 100%;
    max-width: 460px;
    overflow: hidden;
    animation: slideUp 0.25s cubic-bezier(0.34,1.56,0.64,1);
  }

  .modal-header {
    padding: 20px 22px;
    border-bottom: 1px solid var(--border);
    display: flex;
    align-items: center;
    justify-content: space-between;
    background: var(--bg-surface);
  }

  .modal-header h3 {
    font-family: var(--font-display);
    font-size: 17px;
    font-weight: 700;
  }

  .modal-close {
    background: none;
    border: none;
    cursor: pointer;
    color: var(--text-muted);
    font-size: 18px;
    width: 32px;
    height: 32px;
    display: flex;
    align-items: center;
    justify-content: center;
    border-radius: 50%;
    transition: all 0.15s;
  }

  .modal-close:hover { background: var(--bg-glass-hover); color: var(--danger); }

  .modal-body { padding: 22px; }

  .modal-item-list {
    background: var(--bg-surface);
    border: 1px solid var(--border);
    border-radius: 12px;
    padding: 14px 16px;
  }

  .modal-item-row {
    display: flex;
    justify-content: space-between;
    font-size: 13px;
    padding: 4px 0;
    color: var(--text-secondary);
  }

  .modal-footer {
    padding: 16px 22px;
    border-top: 1px solid var(--border);
    display: flex;
    justify-content: flex-end;
    gap: 10px;
    background: var(--bg-surface);
  }

  /* ── SPINNER ── */
  .spinner {
    width: 32px;
    height: 32px;
    border: 3px solid var(--border-strong);
    border-top-color: var(--accent);
    border-radius: 50%;
    animation: spin 0.7s linear infinite;
  }

  .spinner-sm {
    width: 14px;
    height: 14px;
    border: 2px solid rgba(255,255,255,0.35);
    border-top-color: #fff;
    border-radius: 50%;
    animation: spin 0.7s linear infinite;
    display: inline-block;
  }

  @keyframes spin { to { transform: rotate(360deg); } }

  .flex-center { display: flex; align-items: center; justify-content: center; }

  /* ── EMPTY STATE ── */
  .empty-state {
    text-align: center;
    padding: 60px 20px;
    color: var(--text-muted);
    grid-column: 1 / -1;
  }

  .empty-icon { font-size: 52px; margin-bottom: 14px; }

  /* ── SUCCESS BOX ── */
  .success-box {
    background: var(--success-bg);
    border: 1px solid var(--success);
    border-radius: 12px;
    padding: 12px 16px;
    text-align: center;
    color: var(--success);
    font-weight: 700;
    font-size: 13px;
    margin-bottom: 10px;
  }

  /* ── SCROLLBAR ── */
  ::-webkit-scrollbar { width: 5px; height: 5px; }
  ::-webkit-scrollbar-track { background: transparent; }
  ::-webkit-scrollbar-thumb { background: var(--border-strong); border-radius: 10px; }
  ::-webkit-scrollbar-thumb:hover { background: var(--accent); }
`;

/* ─── COMPONENT ───────────────────────────────────────────────────────────── */
export default function WaiterPanel() {
  const [tables, setTables] = useState([]);
  const [menu, setMenu] = useState([]);
  const [specials, setSpecials] = useState({});
  const [selectedTable, setSelectedTable] = useState(null);
  const [allRounds, setAllRounds] = useState([]);
  const [draftRoundIdx, setDraftRoundIdx] = useState(null);
  const [loading, setLoading] = useState(true);
  const [roundLoading, setRoundLoading] = useState(false);
  const [view, setView] = useState("tables");
  const [confirmModal, setConfirmModal] = useState(false);
  const [confirming, setConfirming] = useState(false);
  const [activeOrderType, setActiveOrderType] = useState("table");
  const [taxSettings, setTaxSettings] = useState(null);
  const { user, logout, theme, toggleTheme } = useAuth();
  const navigate = useNavigate();
  const summaryRef = useRef(null);

  /* inject styles */
  useEffect(() => {
    const id = "wp-styles";
    if (!document.getElementById(id)) {
      const tag = document.createElement("style");
      tag.id = id;
      tag.textContent = styles;
      document.head.appendChild(tag);
    }
  }, []);

  /* sync theme to data-theme attribute */
  useEffect(() => {
    document.documentElement.setAttribute("data-theme", theme === "dark" ? "dark" : "light");
  }, [theme]);

  const loadData = useCallback(async () => {
    try {
      const [t, m, s, tax] = await Promise.all([
        API.get("/tables"),
        API.get("/menu"),
        API.get("/extras/specials"),
        API.get("/extras/tax-settings"),
      ]);
      setTables(t.data);
      setMenu(m.data.filter(i => i.is_available));
      const sMap = {};
      s.data.forEach(sp => {
        sMap[sp.menu_id] = {
          ...sp,
          discounted_price: sp.discount_pct > 0
            ? Math.round(sp.price * (1 - sp.discount_pct / 100))
            : sp.price,
        };
      });
      setSpecials(sMap);
      setTaxSettings(tax.data);
    } catch {}
    setLoading(false);
  }, []);

  useEffect(() => { loadData(); }, [loadData]);

  const loadTableRounds = useCallback(async (table) => {
    setRoundLoading(true);
    try {
      const allOrdersRes = await API.get(`/orders/table/${table.id}/all`);
      const orders = allOrdersRes.data || [];
      if (orders.length === 0) {
        setAllRounds([]); setDraftRoundIdx(null); setRoundLoading(false); return;
      }
      const roundsWithItems = await Promise.all(
        orders.map(async (order, idx) => {
          try {
            const detail = await API.get(`/orders/${order.id}`);
            return { order: detail.data.order, items: detail.data.items || [], roundNumber: idx + 1 };
          } catch { return { order, items: [], roundNumber: idx + 1 }; }
        })
      );
      setAllRounds(roundsWithItems);
      const draftIdx = roundsWithItems.findIndex(r => r.order.status === "draft");
      setDraftRoundIdx(draftIdx === -1 ? null : draftIdx);
    } catch {}
    setRoundLoading(false);
  }, []);

  const selectTable = async (table) => {
    setSelectedTable(table); setActiveOrderType("table"); setView("order");
    await loadTableRounds(table);
  };

  const refreshRound = async (roundIdx) => {
    const round = allRounds[roundIdx]; if (!round) return;
    try {
      const detail = await API.get(`/orders/${round.order.id}`);
      setAllRounds(prev => {
        const u = [...prev];
        u[roundIdx] = { ...u[roundIdx], order: detail.data.order, items: detail.data.items || [] };
        return u;
      });
    } catch {}
  };

  const startOrder = async () => {
    if (!selectedTable) return;
    setRoundLoading(true);
    try {
      const res = await API.post("/orders", { table_id: selectedTable.id, order_type: "table" });
      setAllRounds([{ order: res.data, items: [], roundNumber: 1 }]);
      setDraftRoundIdx(0);
      await loadData();
    } catch (err) {
      if (err.response?.data?.order_id) await loadTableRounds(selectedTable);
    }
    setRoundLoading(false);
  };

  const startNewRound = async () => {
    if (!selectedTable || allRounds.some(r => r.order.status === "draft")) return;
    setRoundLoading(true);
    try {
      const res = await API.post("/orders", { table_id: selectedTable.id, order_type: "table", addendum: true });
      const newRound = { order: res.data, items: [], roundNumber: allRounds.length + 1 };
      setAllRounds(prev => [...prev, newRound]);
      setDraftRoundIdx(allRounds.length);
      setTimeout(() => {
        summaryRef.current?.scrollTo({ top: summaryRef.current.scrollHeight, behavior: "smooth" });
      }, 200);
    } catch {}
    setRoundLoading(false);
  };

  const startTakeaway = async () => {
    setRoundLoading(true);
    try {
      const res = await API.post("/orders", { order_type: "takeaway" });
      setAllRounds([{ order: res.data, items: [], roundNumber: 1 }]);
      setDraftRoundIdx(0);
      setSelectedTable(null);
      setActiveOrderType("takeaway");
    } catch {}
    setRoundLoading(false);
    setView("order");
  };

  const addItem = async (menuItem) => {
    if (draftRoundIdx === null) return;
    const draftRound = allRounds[draftRoundIdx];
    if (!draftRound || draftRound.order.status !== "draft") return;
    const special = specials[menuItem.id];
    const unit_price = special ? special.discounted_price : menuItem.price;
    try {
      await API.post(`/orders/${draftRound.order.id}/items`, { menu_id: menuItem.id, quantity: 1, unit_price });
      await refreshRound(draftRoundIdx);
    } catch {}
  };

  const removeItem = async (itemId) => {
    if (draftRoundIdx === null) return;
    const draftRound = allRounds[draftRoundIdx];
    if (!draftRound || draftRound.order.status !== "draft") return;
    try {
      await API.delete(`/orders/${draftRound.order.id}/items/${itemId}`);
      await refreshRound(draftRoundIdx);
    } catch {}
  };

  const handleSendToKitchen = async () => {
    if (draftRoundIdx === null) return;
    const draftRound = allRounds[draftRoundIdx];
    if (!draftRound || draftRound.items.length === 0) return;
    setConfirming(true);
    try {
      await API.put(`/orders/${draftRound.order.id}/confirm`);
      await refreshRound(draftRoundIdx);
      setDraftRoundIdx(null);
      setConfirmModal(false);
      await loadData();
    } catch {}
    setConfirming(false);
  };

  const handleLogout = async () => {
    try { await API.post("/auth/logout"); } catch {}
    logout(); navigate("/");
  };

  const goBack = () => {
    setView("tables"); setAllRounds([]); setDraftRoundIdx(null); setSelectedTable(null); loadData();
  };

  /* computed */
  const categories = [...new Set(menu.map(m => m.category))];
  const catIcons = { food: "🍛", drink: "🥤", dessert: "🍰", snack: "🍿" };
  const roundColors = ["#c4873a", "#10b981", "#8b5cf6", "#ec4899", "#06b6d4", "#f59e0b"];
  const combinedTotal = allRounds.reduce((s, r) => s + Number(r.order?.total || 0), 0);
  const taxRate = taxSettings ? (parseFloat(taxSettings.tax_rate) || 13) : 13;
  const taxEnabled = taxSettings ? taxSettings.tax_enabled !== false : false;
  const taxAmount = taxEnabled ? parseFloat((combinedTotal * taxRate / 100).toFixed(2)) : 0;
  const grandTotalWithTax = parseFloat((combinedTotal + taxAmount).toFixed(2));
  const hasSentRounds = allRounds.some(r => r.order.status !== "draft");
  const draftRound = draftRoundIdx !== null ? allRounds[draftRoundIdx] : null;
  const canAddItems = draftRound !== null && draftRound.order.status === "draft";

  const getRoundLabel = idx => ["Round 1","Round 2","Round 3","Round 4","Round 5","Round 6","Round 7","Round 8"][idx] || `Round ${idx + 1}`;
  const getRoundOrdinal = idx => ["1st","2nd","3rd","4th","5th","6th","7th","8th"][idx] || `${idx + 1}th`;

  return (
    <div className="wp-root">

      {/* ── HEADER ─────────────────────────────────────────────────────── */}
      <header className="wp-header">
        <div className="wp-logo">
          <div className="wp-logo-icon">🧑‍🍽️</div>
          <div>
            <div className="wp-logo-title">Waiter Panel</div>
            <div className="wp-logo-sub">{user?.restaurant_name} · {user?.name}</div>
          </div>
        </div>
        <div className="wp-header-actions">
          {view === "order" && (
            <button className="btn btn-secondary btn-sm" onClick={goBack}>← Tables</button>
          )}
          <button className="theme-toggle" onClick={toggleTheme} title="Toggle theme">
            <span>{theme === "dark" ? "🌙" : "☀️"}</span>
            <div className="toggle-track"><div className="toggle-thumb" /></div>
          </button>
          <button className="btn btn-ghost" onClick={handleLogout} title="Logout">🚪</button>
        </div>
      </header>

      <div className="wp-content">

        {/* ══ TABLES VIEW ═══════════════════════════════════════════════ */}
        {view === "tables" && (
          <>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: 10, marginBottom: 22 }}>
              <div className="section-heading">Select a Table</div>
              <div style={{ display: "flex", gap: 10 }}>
                <button className="btn btn-takeaway" onClick={startTakeaway}>
                  📦 New Takeaway
                </button>
                <button className="btn btn-secondary btn-sm" onClick={loadData}>↻ Refresh</button>
              </div>
            </div>

            {Object.keys(specials).length > 0 && (
              <div className="specials-banner">
                <span style={{ fontSize: 20 }}>⭐</span>
                <span style={{ fontWeight: 800, color: "var(--warning)", fontSize: 13, fontFamily: "var(--font-display)" }}>
                  Today's Specials:
                </span>
                {Object.values(specials).map((sp, i) => (
                  <span key={i} className="special-badge">
                    {sp.name} — Rs.{sp.discounted_price}
                    {sp.label ? ` "${sp.label}"` : ""}
                    {sp.discount_pct > 0 ? ` (${sp.discount_pct}% off)` : ""}
                  </span>
                ))}
              </div>
            )}

            {loading ? (
              <div className="flex-center" style={{ padding: 80 }}><div className="spinner" /></div>
            ) : (
              <div className="table-grid">
                {tables.map(t => (
                  <div key={t.id} className={`table-tile ${t.status}`} onClick={() => selectTable(t)}>
                    <div className="tile-num">T{t.table_number}</div>
                    <div className="tile-status">{t.status}</div>
                    {t.status === "reserved" && t.reserved_by_name && (
                      <div style={{ fontSize: 10, color: "var(--accent-2)", marginTop: 5, fontWeight: 600 }}>
                        📋 {t.reserved_by_name}
                      </div>
                    )}
                    <div style={{ fontSize: 11, color: "var(--text-muted)", marginTop: 5 }}>👥 {t.capacity}</div>
                  </div>
                ))}
                {tables.length === 0 && (
                  <div className="empty-state">
                    <div className="empty-icon">🪑</div>
                    <h3 style={{ fontFamily: "var(--font-display)" }}>No tables configured</h3>
                  </div>
                )}
              </div>
            )}
          </>
        )}

        {/* ══ ORDER VIEW ════════════════════════════════════════════════ */}
        {view === "order" && (
          <div className="order-layout">

            {/* LEFT — MENU */}
            <div>
              {/* Status row */}
              <div style={{ marginBottom: 18, display: "flex", alignItems: "center", gap: 10, flexWrap: "wrap" }}>
                {activeOrderType === "takeaway" ? (
                  <div className="badge badge-takeaway">📦 TAKEAWAY ORDER</div>
                ) : (
                  <div className="badge badge-table">🪑 Table {selectedTable?.table_number}</div>
                )}

                {allRounds.map((r, idx) =>
                  r.order.status !== "draft" && (
                    <span key={idx} className="badge badge-sent" style={{
                      color: roundColors[idx % roundColors.length],
                      borderColor: `${roundColors[idx % roundColors.length]}50`,
                      background: `${roundColors[idx % roundColors.length]}12`,
                    }}>
                      ✅ {getRoundLabel(idx)} sent
                    </span>
                  )
                )}

                {draftRoundIdx !== null && (
                  <span className="badge badge-sent" style={{
                    color: "#d97706", borderColor: "rgba(217,119,6,0.40)", background: "rgba(217,119,6,0.10)",
                  }}>
                    ✏️ Taking {getRoundOrdinal(draftRoundIdx)} order
                  </span>
                )}
              </div>

              {roundLoading ? (
                <div className="flex-center" style={{ padding: 80 }}><div className="spinner" /></div>
              ) : allRounds.length === 0 ? (
                <div className="glass-card" style={{ textAlign: "center", padding: "60px 30px" }}>
                  <div style={{ fontSize: 52, marginBottom: 16 }}>🪑</div>
                  <div style={{ fontFamily: "var(--font-display)", fontSize: 20, fontWeight: 700, marginBottom: 8 }}>
                    {activeOrderType === "takeaway" ? "New Takeaway Order" : `Table ${selectedTable?.table_number} is free`}
                  </div>
                  {activeOrderType === "table" && (
                    <button className="btn btn-primary" style={{ marginTop: 12, padding: "11px 28px", fontSize: 15 }} onClick={startOrder}>
                      🍽️ Start New Order
                    </button>
                  )}
                </div>
              ) : (
                <>
                  {hasSentRounds && draftRoundIdx === null && activeOrderType !== "takeaway" && (
                    <div className="new-round-prompt">
                      <div>
                        <div style={{ fontWeight: 700, fontSize: 14 }}>Need more items?</div>
                        <div style={{ fontSize: 12, color: "var(--text-muted)", marginTop: 2 }}>
                          Start a new round — only new items are sent to the kitchen.
                        </div>
                      </div>
                      <button className="btn btn-primary btn-sm" onClick={startNewRound} style={{ fontWeight: 800 }}>
                        ➕ Add {getRoundOrdinal(allRounds.length)} Order
                      </button>
                    </div>
                  )}

                  {categories.map(cat => {
                    const items = menu.filter(m => m.category === cat);
                    return (
                      <div key={cat} style={{ marginBottom: 24 }}>
                        <div className="menu-cat-label">{catIcons[cat]} {cat}</div>
                        <div className="menu-grid">
                          {items.map(item => {
                            const special = specials[item.id];
                            const displayPrice = special ? special.discounted_price : item.price;
                            return (
                              <button
                                key={item.id}
                                className={`menu-item-card ${special ? "is-special" : ""}`}
                                onClick={() => addItem(item)}
                                disabled={!canAddItems}
                              >
                                {special && (
                                  <div className="special-ribbon">
                                    {special.label || `${special.discount_pct}% OFF`}
                                  </div>
                                )}
                                <div className="item-name">{item.name}</div>
                                <div style={{ display: "flex", alignItems: "center", gap: 7 }}>
                                  <span className="item-price">Rs. {Number(displayPrice).toLocaleString()}</span>
                                  {special && special.discount_pct > 0 && (
                                    <span className="item-price-old">Rs. {Number(item.price).toLocaleString()}</span>
                                  )}
                                </div>
                              </button>
                            );
                          })}
                        </div>
                      </div>
                    );
                  })}
                </>
              )}
            </div>

            {/* RIGHT — ORDER SUMMARY */}
            <div className="order-panel">
              <div className="order-panel-header">
                <div>
                  <div className="order-panel-title">Order Summary</div>
                  <div className="order-panel-sub">
                    {activeOrderType === "takeaway"
                      ? "📦 Takeaway"
                      : selectedTable
                      ? `Table ${selectedTable.table_number} · ${allRounds.length} round${allRounds.length !== 1 ? "s" : ""}`
                      : "No active order"}
                  </div>
                </div>
                {allRounds.length > 0 && (
                  <span style={{
                    background: "var(--success-bg)", color: "var(--success)",
                    border: "1px solid var(--success)", borderRadius: 20,
                    padding: "4px 12px", fontSize: 11, fontWeight: 700,
                  }}>
                    {allRounds.filter(r => r.order.status !== "draft").length}/{allRounds.length} sent
                  </span>
                )}
              </div>

              <div ref={summaryRef} style={{ maxHeight: "calc(100vh - 340px)", overflowY: "auto" }}>
                {allRounds.length === 0 && (
                  <div style={{ padding: "36px 20px", textAlign: "center", color: "var(--text-muted)", fontSize: 13 }}>
                    {activeOrderType === "table" ? "Start an order to see items here" : "Add items to takeaway order"}
                  </div>
                )}

                {allRounds.map((round, idx) => {
                  const isSent = round.order.status !== "draft";
                  const isDraft = round.order.status === "draft";
                  const color = roundColors[idx % roundColors.length];
                  return (
                    <div key={round.order.id}>
                      <div className="round-header" style={{
                        background: isDraft ? `${color}10` : "var(--bg-surface)",
                        borderTop: idx > 0 ? `2px solid var(--border)` : "none",
                      }}>
                        <span className="round-label" style={{ color: isDraft ? color : "var(--text-muted)" }}>
                          {getRoundLabel(idx)}
                          {isDraft && <span style={{ fontWeight: 500, textTransform: "none", marginLeft: 6, fontSize: 10 }}>(adding…)</span>}
                        </span>
                        {isSent
                          ? <span style={{ fontSize: 11, color: "var(--success)", fontWeight: 700 }}>✅ Sent</span>
                          : <span style={{ fontSize: 11, color, fontWeight: 600 }}>✏️ Draft</span>
                        }
                      </div>

                      <div>
                        {round.items.length === 0 ? (
                          <div style={{ padding: "14px 18px", textAlign: "center", color: "var(--text-muted)", fontSize: 12 }}>
                            Tap menu items to add
                          </div>
                        ) : round.items.map(item => (
                          <div key={item.id} className="order-item-row" style={{ background: isDraft ? `${color}05` : "transparent" }}>
                            <div style={{ flex: 1 }}>
                              <div style={{ fontWeight: 600, fontSize: 13 }}>{item.name}</div>
                              <div style={{ fontSize: 11, color: "var(--text-muted)" }}>×{item.quantity}</div>
                            </div>
                            <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                              <span style={{ fontWeight: 800, color: isDraft ? color : "var(--success)", fontSize: 13 }}>
                                Rs. {Number(item.price).toLocaleString()}
                              </span>
                              {isDraft && (
                                <button className="remove-btn" onClick={() => removeItem(item.id)}>×</button>
                              )}
                            </div>
                          </div>
                        ))}
                      </div>

                      <div style={{
                        padding: "8px 18px", display: "flex", justifyContent: "space-between",
                        fontSize: 12, background: "var(--bg-surface)", borderBottom: "1px solid var(--border)",
                      }}>
                        <span style={{ color: "var(--text-muted)" }}>{getRoundLabel(idx)} subtotal</span>
                        <span style={{ fontWeight: 700, color: isSent ? "var(--text-primary)" : color }}>
                          Rs. {Number(round.order?.total || 0).toLocaleString()}
                        </span>
                      </div>
                    </div>
                  );
                })}
              </div>

              {/* Grand total */}
              {allRounds.length > 0 && (
                <div className="order-total-bar">
                  {taxEnabled && (
                    <>
                      <div style={{ display: "flex", justifyContent: "space-between", fontSize: 12, color: "var(--text-muted)", marginBottom: 4 }}>
                        <span>Subtotal</span>
                        <span>Rs. {combinedTotal.toLocaleString()}</span>
                      </div>
                      <div style={{ display: "flex", justifyContent: "space-between", fontSize: 12, color: "var(--text-muted)", marginBottom: 8 }}>
                        <span>VAT ({taxRate}%)</span>
                        <span>Rs. {taxAmount.toLocaleString()}</span>
                      </div>
                    </>
                  )}
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                    <div>
                      <div style={{ fontWeight: 700, fontSize: 14 }}>Grand Total</div>
                      {taxEnabled && <div style={{ fontSize: 10, color: "var(--text-muted)" }}>VAT inclusive</div>}
                    </div>
                    <span className="grand-total-amount">Rs. {grandTotalWithTax.toLocaleString()}</span>
                  </div>
                </div>
              )}

              {/* Send to kitchen */}
              {draftRound && draftRound.items.length > 0 && (
                <div style={{ padding: "14px 18px", borderTop: "1px solid var(--border)" }}>
                  <button
                    className="btn btn-primary"
                    style={{
                      width: "100%", fontWeight: 800, fontSize: 15, padding: "13px 0",
                      background: `linear-gradient(135deg, ${roundColors[draftRoundIdx % roundColors.length]}, ${roundColors[(draftRoundIdx + 1) % roundColors.length]})`,
                      boxShadow: `0 6px 20px ${roundColors[draftRoundIdx % roundColors.length]}50`,
                      borderRadius: 12,
                    }}
                    onClick={() => setConfirmModal(true)}
                  >
                    🚀 Send {getRoundLabel(draftRoundIdx)} to Kitchen
                  </button>
                  <div style={{ fontSize: 11, color: "var(--text-muted)", textAlign: "center", marginTop: 7 }}>
                    Only these new items will be sent — no duplication
                  </div>
                </div>
              )}

              {/* All sent */}
              {allRounds.length > 0 && draftRoundIdx === null && (
                <div style={{ padding: "14px 18px", borderTop: "1px solid var(--border)" }}>
                  <div className="success-box">✅ All rounds sent to kitchen</div>
                  {activeOrderType !== "takeaway" && (
                    <button className="btn btn-secondary btn-sm" style={{ width: "100%", fontWeight: 700 }} onClick={startNewRound}>
                      ➕ Add {getRoundOrdinal(allRounds.length)} Order
                    </button>
                  )}
                </div>
              )}
            </div>
          </div>
        )}
      </div>

      {/* ══ CONFIRM MODAL ══════════════════════════════════════════════ */}
      {confirmModal && draftRound && (
        <div className="modal-overlay" onClick={() => setConfirmModal(false)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h3>🚀 Send {getRoundLabel(draftRoundIdx)} to Kitchen</h3>
              <button className="modal-close" onClick={() => setConfirmModal(false)}>✕</button>
            </div>
            <div className="modal-body">
              <div style={{ textAlign: "center", marginBottom: 20 }}>
                <div style={{ fontSize: 44, marginBottom: 12 }}>
                  {activeOrderType === "takeaway" ? "📦" : draftRoundIdx === 0 ? "🍽️" : "➕"}
                </div>
                <div style={{ fontFamily: "var(--font-display)", fontWeight: 700, fontSize: 17, marginBottom: 6 }}>
                  {activeOrderType === "takeaway"
                    ? "Send Takeaway to Kitchen?"
                    : draftRoundIdx === 0
                    ? `Send 1st Order for Table ${selectedTable?.table_number}?`
                    : `Send ${getRoundOrdinal(draftRoundIdx)} order for Table ${selectedTable?.table_number}?`}
                </div>
                {draftRoundIdx > 0 && (
                  <div style={{ color: "var(--text-muted)", fontSize: 13 }}>
                    Only these new items will go to kitchen — previous rounds are excluded.
                  </div>
                )}
              </div>

              <div className="modal-item-list">
                <div style={{ fontSize: 10, fontWeight: 800, color: "var(--text-muted)", textTransform: "uppercase", letterSpacing: 1.5, marginBottom: 12 }}>
                  Items for {getRoundLabel(draftRoundIdx)}
                </div>
                {draftRound.items.map((item, i) => (
                  <div key={i} className="modal-item-row">
                    <span>{item.name}</span>
                    <span style={{ color: "var(--text-muted)" }}>×{item.quantity}</span>
                  </div>
                ))}
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn btn-secondary" onClick={() => setConfirmModal(false)}>Cancel</button>
              <button
                className="btn btn-primary"
                style={{ fontWeight: 800, minWidth: 140 }}
                onClick={handleSendToKitchen}
                disabled={confirming}
              >
                {confirming ? <><span className="spinner-sm" /> Sending…</> : "✅ Confirm & Send"}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
